-- Make clangd play nice with PlatformIO / ESP32 GCC toolchains.
--
-- clangd reads compile_commands.json (generated by `pio run -t compiledb`)
-- for the project's own include paths, but it will NOT trust the embedded
-- GCC toolchain's *built-in* headers (stdint.h, <cstdint>, etc.) unless we
-- explicitly allow it to query that compiler. Without --query-driver you get
-- "unknown type name 'uint8_t'" even when Arduino.h resolves fine.
return {
  "neovim/nvim-lspconfig",
  opts = {
    servers = {
      clangd = {
        cmd = {
          "clangd",
          "--background-index",
          "--clang-tidy",
          "--header-insertion=iwyu",
          "--completion-style=detailed",
          "--function-arg-placeholders",
          "--fallback-style=llvm",
          -- Allow clangd to invoke the ESP32 GCC drivers to discover their
          -- built-in system include paths. Covers both RISC-V (C3/C6/H2)
          -- and Xtensa (classic ESP32/S2/S3) toolchains.
          -- clangd does its own globbing here, so pass the pattern literally
          -- (only expand ~). Matches *-elf-gcc and *-elf-g++.
          "--query-driver=" .. vim.fn.expand("~") .. "/.platformio/packages/**/bin/*-elf-g*",
        },
      },
    },
  },
}
